mapper.select:
select * from (select r.*, string_agg(p.name, ', ' order by p.sort, p.create_time) AS permission_names from sys_role r left join sys_role_permission_relation rel on r.role_id = rel.role_id left join sys_permission p on p.permission_id = rel.permission_id
and (r.role_name like concat('%', #{dto.keyword}, '%') or r.remark like concat('%', #{dto.keyword}, '%')
or r.role_id = CAST(#{dto.keyword} AS BIGINT)
)
and r.create_time >= #{dto.startTime}
and r.create_time <= #{dto.endTime}
group by r.role_id) t order by create_time desc
